#include <numeric>
#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    int frogJump(vector<int>& heights, int K) {
        int n = heights.size();
        vector<int> dp(n, INT_MAX);
        dp[0] = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j <= min(i + K, n - 1); j++) {
                dp[j] = min(dp[j], dp[i] + abs(heights[i] - heights[j]));
            }
        }
        return dp.back();
    }
};
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n, K;
    if (!(cin >> n >> K)) return 0;
    vector<int> heights(n);
    for (int i = 0; i < n; i++) cin >> heights[i];
    Solution sol;
    int ans = sol.frogJump(heights, K);
    cout << ans << "\n";
    return 0;
}
